+impl DataFrameDictResult {
+    pub fn as_mapping(&self) -> Option<&BTreeMap<String, Vec<(String, Scalar)>>> {
+        match self {
+            Self::Mapping(mapping) => Some(mapping),
+            Self::Series(_) => None,
+        }
